import{c as n,S as h,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Tổng quan hệ thống LamSơn Edutech","description":"","frontmatter":{},"headers":[],"relativePath":"gioi-thieu/tong-quan.md","filePath":"gioi-thieu/tong-quan.md","lastUpdated":0}'),e={name:"gioi-thieu/tong-quan.md"};function c(o,t,l,r,s,u){return h(),i("div",null,[...t[0]||(t[0]=[a(`<h1 id="tong-quan-he-thong-lamson-edutech" tabindex="-1">Tổng quan hệ thống LamSơn Edutech <a class="header-anchor" href="#tong-quan-he-thong-lamson-edutech" aria-label="Permalink to “Tổng quan hệ thống LamSơn Edutech”">​</a></h1><p>LamSơn Edutech là hệ thống học tập trực tuyến (Learning Management System) chuyên sâu cho <strong>luyện thi Đại học tại Việt Nam</strong>, bao gồm:</p><ul><li>Kỳ thi <strong>Đánh giá năng lực (ĐGNL/HSA)</strong> của ĐHQG Hà Nội</li><li>Kỳ thi <strong>Đánh giá tư duy (ĐGTD/TSA)</strong> của ĐH Bách Khoa Hà Nội</li><li>Kỳ thi <strong>Tốt nghiệp THPT</strong></li><li>Các bài <strong>kiểm tra đầu vào</strong>, <strong>ôn thi THCS/THPT</strong></li><li><strong>Học liệu, giáo trình</strong> và <strong>bộ đề thi</strong></li></ul><h2 id="he-thong-co-gi" tabindex="-1">Hệ thống có gì? <a class="header-anchor" href="#he-thong-co-gi" aria-label="Permalink to “Hệ thống có gì?”">​</a></h2><p>Hệ thống gồm 3 nhóm người dùng chính, mỗi nhóm có khu vực làm việc riêng:</p><h3 id="_1-khu-vuc-hoc-vien-https-lamsonedutech-vn-luyen-tap-hoac-https-lamsonedutech-vn-home" tabindex="-1">1. Khu vực Học viên (<code>https://lamsonedutech.vn/luyen-tap/...</code> hoặc <code>https://lamsonedutech.vn/home</code>) <a class="header-anchor" href="#_1-khu-vuc-hoc-vien-https-lamsonedutech-vn-luyen-tap-hoac-https-lamsonedutech-vn-home" aria-label="Permalink to “1. Khu vực Học viên (https://lamsonedutech.vn/luyen-tap/... hoặc https://lamsonedutech.vn/home)”">​</a></h3><ul><li>Đăng ký tài khoản, mua khóa học, tham gia học.</li><li>Học bài giảng video, làm bài luyện tập theo chuyên đề/module.</li><li>Làm bài thi thử ĐGNL, ĐGTD, Tốt nghiệp THPT, bài kiểm tra đầu vào.</li><li>Xem lại bài thi, lịch sử làm bài, bảng xếp hạng.</li><li>Đặt câu hỏi cho giáo viên (Hỏi đáp).</li></ul><h3 id="_2-khu-vuc-giao-vien-https-lamsonedutech-vn-teacher" tabindex="-1">2. Khu vực Giáo viên (<code>https://lamsonedutech.vn/teacher/...</code>) <a class="header-anchor" href="#_2-khu-vuc-giao-vien-https-lamsonedutech-vn-teacher" aria-label="Permalink to “2. Khu vực Giáo viên (https://lamsonedutech.vn/teacher/...)”">​</a></h3><ul><li>Tạo và quản lý khóa học, chương học, chuyên đề, bài giảng.</li><li>Quản lý lớp học và danh sách học viên trong lớp.</li><li>Tạo tiêu chí đề thi, ra đề và chấm điểm thi.</li><li>Trả lời câu hỏi của học viên.</li></ul><h3 id="_3-khu-vuc-quan-tri-https-lamsonedutech-vn-admin" tabindex="-1">3. Khu vực Quản trị (<code>https://lamsonedutech.vn/admin/...</code>) <a class="header-anchor" href="#_3-khu-vuc-quan-tri-https-lamsonedutech-vn-admin" aria-label="Permalink to “3. Khu vực Quản trị (https://lamsonedutech.vn/admin/...)”">​</a></h3><ul><li>Quản lý toàn bộ thành viên (học viên, giáo viên, nhân viên) và phân quyền.</li><li>Quản lý khung chương trình, khóa học, đề thi mẫu, câu hỏi.</li><li>Quản lý kinh doanh: khuyến mãi, chiết khấu, đại lý, hóa đơn.</li><li>Cấu hình hệ thống: banner, menu, footer, thông tin ngân hàng, liên hệ.</li><li>Xem thống kê tổng thể: khóa học, giáo viên, học viên, kết quả thi.</li></ul><h2 id="cac-loai-chuong-trinh-đao-tao" tabindex="-1">Các loại chương trình đào tạo <a class="header-anchor" href="#cac-loai-chuong-trinh-đao-tao" aria-label="Permalink to “Các loại chương trình đào tạo”">​</a></h2><p>Hệ thống phân loại các chương trình thành những nhóm sau:</p><table tabindex="0"><thead><tr><th>#</th><th>Loại chương trình</th><th>Mô tả</th></tr></thead><tbody><tr><td>1</td><td><strong>Kiểm tra đầu vào</strong></td><td>Bài test phân loại trình độ trước khi vào khóa học chính</td></tr><tr><td>2</td><td><strong>Thi thử ĐGNL</strong></td><td>Mô phỏng kỳ thi HSA của ĐHQG Hà Nội</td></tr><tr><td>3</td><td><strong>Thi thử ĐGTD</strong></td><td>Mô phỏng kỳ thi TSA của ĐH Bách Khoa Hà Nội</td></tr><tr><td>4</td><td><strong>Thi tốt nghiệp THPT</strong></td><td>Đề thi thử tốt nghiệp THPT từng môn</td></tr><tr><td>5</td><td><strong>Luyện thi ĐGNL, ĐGTD</strong></td><td>Khóa học luyện chuyên sâu cho HSA &amp; TSA</td></tr><tr><td>6</td><td><strong>Ôn thi TN THCS, THPT</strong></td><td>Khóa ôn luyện cho học sinh THCS, THPT</td></tr><tr><td>7</td><td><strong>Học liệu, giáo trình</strong></td><td>Tài liệu, sách điện tử dùng cho học tập</td></tr><tr><td>8</td><td><strong>Bộ đề thi</strong></td><td>Tổng hợp các đề thi theo bộ để luyện đều</td></tr></tbody></table><h2 id="cau-truc-mot-khoa-hoc" tabindex="-1">Cấu trúc một khóa học <a class="header-anchor" href="#cau-truc-mot-khoa-hoc" aria-label="Permalink to “Cấu trúc một khóa học”">​</a></h2><p>Mỗi khóa học trên LamSơn Edutech được tổ chức theo cây phân cấp:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Khóa học</span></span>
<span class="line"><span>└── Chương học</span></span>
<span class="line"><span>    └── Chuyên đề</span></span>
<span class="line"><span>        └── Bài giảng (video, tài liệu)</span></span>
<span class="line"><span>        └── Bài luyện tập / Đề kiểm tra</span></span></code></pre></div><ul><li><strong>Khóa học</strong> thuộc về một <strong>Khung chương trình</strong> (do Admin quản lý).</li><li>Mỗi <strong>Chương / Chuyên đề</strong> có thể chứa nhiều <strong>bài giảng</strong> và <strong>đề kiểm tra cuối chuyên đề</strong>.</li><li>Học viên hoàn thành chuyên đề trước mới mở khóa được chuyên đề sau (tùy cấu hình khóa học).</li></ul><h2 id="yeu-cau-he-thong" tabindex="-1">Yêu cầu hệ thống <a class="header-anchor" href="#yeu-cau-he-thong" aria-label="Permalink to “Yêu cầu hệ thống”">​</a></h2><ul><li>Trình duyệt: <strong>Google Chrome, Microsoft Edge, Firefox, Safari</strong> phiên bản mới (khuyên dùng Chrome ≥ 100).</li><li>Kết nối Internet ổn định, đặc biệt khi làm bài thi online có thời gian giới hạn.</li><li>Máy tính, laptop hoặc tablet có màn hình ≥ 10 inch để hiển thị đề thi đầy đủ.</li><li>Trên điện thoại vẫn dùng được nhưng khuyến nghị máy tính khi thi.</li></ul><h2 id="tiep-theo" tabindex="-1">Tiếp theo <a class="header-anchor" href="#tiep-theo" aria-label="Permalink to “Tiếp theo”">​</a></h2><ul><li><a href="./tai-khoan-va-vai-tro">Tài khoản và vai trò</a> - phân biệt 3 vai trò chính</li><li><a href="./dang-nhap">Đăng nhập / Đăng ký</a> - bắt đầu sử dụng</li><li><a href="./cac-loai-ky-thi">Các loại kỳ thi</a> - tìm hiểu kỳ thi phù hợp với bạn</li></ul>`,22)])])}const p=n(e,[["render",c]]);export{d as __pageData,p as default};
